fn trimming_select_list(
    attrs: &[crate::parser::entity::Attribute],
    index: usize,
    entity_id: u64,
    field: &'static str,
) -> Result<Vec<super::model::EarlyTrimSelect>, crate::ir::error::ConvertError> {
    let Some(crate::parser::entity::Attribute::List(items)) = attrs.get(index) else {
        return Err(crate::ir::error::ConvertError::UnexpectedEntityForm {
            entity_id,
            detail: format!("{field}: expected list"),
        });
    };
    let mut out = Vec::with_capacity(items.len());
    for item in items {
        match bind_trimming_select(item) {
            Some(v) => out.push(v),
            None => {
                return Err(crate::ir::error::ConvertError::UnexpectedEntityForm {
                    entity_id,
                    detail: format!("{field}: unrecognized trimming_select in list"),
                });
            }
        }
    }
    Ok(out)
}
